sql:
SELECT c.name
FROM courses c
WHERE c.course_id = (SELECT MIN(course_id) FROM courses);

SELECT courses.course_id, courses.name, course_evaluations.evaluation
FROM courses
LEFT JOIN course_evaluations ON courses.course_id = course_evaluations.course_id;

SELECT students.student_name, course_evaluations.evaluation
FROM students
INNER JOIN course_evaluations ON students.student_id = course_evaluations.student_id;

SELECT c.code, c.name, (c.internal_enrollment + c.external_enrollment) AS total_enrollments
FROM courses c
WHERE (c.internal_enrollment + c.external_enrollment) > 100;

SELECT course_id, AVG(credit_hours) AS average_credit_hours
FROM course_credits
GROUP BY course_id;

SELECT faculty.faculty_name
FROM faculty
INNER JOIN course_instructors ON faculty.faculty_id = course_instructors.faculty_id
WHERE course_instructors.course_id IN (
    SELECT course_id FROM prerequisites WHERE prerequisite_course_id IN (
        SELECT corequisite_course_id FROM corequisites WHERE course_id = 1
    )
);

SELECT *
FROM course_evaluations
JOIN courses ON course_evaluations.course_id = courses.course_id;
